ript"},"content":[{"type":"text","text":"const { Duplex } = require('stream');

class MyDuplex extends Duplex {
  constructor(options) {
    super(options);
    this.data = ['Привет', 'из', 'Duplex!'];
  }

  // Реализация чтения
  _read() {
    if (this.data.length === 0) {
      this.push(null); // сигнал окончания
    } else {
      const chunk = this.data.shift();
      this.push(chunk);
    }
  }

  // Реализация записи
  _write(chunk, encoding, callback) {
    console.log('Записано:', chunk.toString());
    callback(); // обязательно вызывать callback!
  }
}

const duplex = new MyDuplex();

duplex.on('data', (chunk) => {
  console.log('Прочитано:', chunk.toString());
});

duplex.write('Hello');
duplex.write('World');
duplex.end();
