"attrs":{"language":"javascript"},"content":[{"type":"text","text":"const { Transform } = require('stream');

class UpperCaseTransform extends Transform {
  constructor(options) {
    super(options);
  }

  _transform(chunk, encoding, callback) {
    const transformed = chunk.toString().toUpperCase();
    this.push(transformed); // передаём результат дальше
    callback(); // сигнал, что обработка завершена
  }
}

const upperCase = new UpperCaseTransform();

